class SecureModelDownloader:
    """Secure model downloader with checksum verification"""
    
    def __init__(self, cache_dir: str = "./model_cache"):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.trusted_sources = {
            "pytorch": "https://download.pytorch.org/models/",
            "huggingface": "https://huggingface.co/",
        }
        self.checksum_registry = {}
    
    def register_model(self, name: str, url: str, sha256: str, source: str = "custom"):
        """Register a model with its expected checksum"""
        self.checksum_registry[name] = {
            "url": url,
            "sha256": sha256,
            "source": source
        }
    
    def verify_checksum(self, filepath: Path, expected_sha256: str) -> bool:
        """Verify file integrity using SHA256 checksum"""
        sha256_hash = hashlib.sha256()
        with open(filepath, "rb") as f:
            for byte_block in iter(lambda: f.read(4096), b""):
                sha256_hash.update(byte_block)
        computed_hash = sha256_hash.hexdigest()
        return computed_hash == expected_sha256
    
    def download_model(self, model_name: str, force_download: bool = False) -> Path:
        """Download model with checksum verification"""
        if model_name not in self.checksum_registry:
            raise ValueError(f"Model {model_name} not registered. Please register with checksum first.")
        
        model_info = self.checksum_registry[model_name]
        url = model_info["url"]
        expected_sha256 = model_info["sha256"]
        
        filename = f"{model_name}.pth"
        filepath = self.cache_dir / filename
        
        if filepath.exists() and not force_download:
            if self.verify_checksum(filepath, expected_sha256):
                print(f"Using cached model: {filepath}")
                return filepath
            else:
                warnings.warn(f"Cached model checksum mismatch. Re-downloading...")
                filepath.unlink()
        
        print(f"Downloading model from {url}...")
        response = requests.get(url, stream=True, timeout=30)
        response.raise_for_status()
        
        temp_filepath = filepath.with_suffix('.tmp')
        with open(temp_filepath, 'wb') as f:
            for chunk in response.iter_content(chunk_size=8192):
                f.write(chunk)
        
        if not self.verify_checksum(temp_filepath, expected_sha256):
            temp_filepath.unlink()
            raise ValueError(f"Downloaded model checksum verification failed! Possible tampering detected.")
        
        temp_filepath.rename(filepath)
        print(f"Model downloaded and verified: {filepath}")
        return filepath
    
    def load_model_safe(self, model_name: str, map_location: str = 'cpu') -> Dict:
        """Safely load model with weights_only=True to prevent arbitrary code execution"""
        filepath = self.download_model(model_name)
        
        try:
            # Use weights_only=True to prevent pickle-based code execution attacks
            checkpoint = torch.load(filepath, map_location=map_location, weights_only=True)
            print(f"Model loaded safely from {filepath}")
            return checkpoint
        except Exception as e:
            raise RuntimeError(f"Failed to load model safely: {e}")


class CustomDataset(Dataset):
    """Example custom dataset for fine-tuning"""
    
    def __init__(self, data, labels):
        self.data = torch.FloatTensor(data)
        self.labels = torch.LongTensor(labels)
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        return self.data[idx], self.labels[idx]


class TransferLearningPipeline:
    """Secure transfer learning pipeline"""
    
    def __init__(self, model_downloader: SecureModelDownloader):
        self.downloader = model_downloader
        self.model = None
        self.device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    
    def load_pretrained_model(self, model_name: str, model_architecture: nn.Module):
        """Load pretrained weights into model architecture"""
        checkpoint = self.downloader.load_model_safe(model_name)
        
        # Only load state_dict (weights), not arbitrary objects
        if isinstance(checkpoint, dict) and 'state_dict' in checkpoint:
            state_dict = checkpoint['state_dict']
        else:
            state_dict = checkpoint
        
        # Verify state_dict contains only tensors
        for key, value in state_dict.items():
            if not isinstance(value, torch.Tensor):
                raise ValueError(f"Invalid state_dict: non-tensor value found at key {key}")
        
        model_architecture.load_state_dict(state_dict, strict=False)
        self.model = model_architecture.to(self.device)
        print(f"Pretrained weights loaded into model")
        return self.model
    
    def freeze_layers(self, num_layers_to_freeze: Optional[int] = None):
        """Freeze layers for transfer learning"""
        if self.model is None:
            raise ValueError("Model not loaded")
        
        layers = list(self.model.children())
        if num_layers_to_freeze is None:
            num_layers_to_freeze = len(layers) - 1
        
        for i, layer in enumerate(layers[:num_layers_to_freeze]):
            for param in layer.parameters():
                param.requires_grad = False
        
        print(f"Frozen {num_layers_to_freeze} layers")
    
    def fine_tune(self, train_loader: DataLoader, num_epochs: int = 10, 
                  learning_rate: float = 0.001):
        """Fine-tune model on custom dataset"""
        if self.model is None:
            raise ValueError("Model not loaded")
        
        criterion = nn.CrossEntropyLoss()
        optimizer = optim.Adam(filter(lambda p: p.requires_grad, self.model.parameters()), 
                              lr=learning_rate)
        
        self.model.train()
        for epoch in range(num_epochs):
            total_loss = 0
            for batch_idx, (data, target) in enumerate(train_loader):
                data, target = data.to(self.device), target.to(self.device)
                
                optimizer.zero_grad()
                output = self.model(data)
                loss = criterion(output, target)
                loss.backward()
                optimizer.step()
                
                total_loss += loss.item()
            
            avg_loss = total_loss / len(train_loader)
            print(f"Epoch {epoch+1}/{num_epochs}, Loss: {avg_loss:.4f}")
        
        print("Fine-tuning completed")
    
    def save_model(self, filepath: str):
        """Save fine-tuned model"""
        if self.model is None:
            raise ValueError("Model not loaded")
        
        torch.save({
            'state_dict': self.model.state_dict(),
            'model_type': type(self.model).__name__
        }, filepath)
        print(f"Model saved to {filepath}")


